const _ = require('lodash');
const db = require('../../db');

async function listProblems({ limit, difficulty, tags, includeComponents }) {
  // Base query to fetch problems with optional filters
  let query = db('problems').select('*');

  if (difficulty) {
    query = query.where('difficulty', difficulty);
  }

  if (tags && tags.length > 0) {
    query = query.whereRaw('tags @> ?', [tags]);
  }

  // Apply limit
  if (limit) {
    query = query.limit(limit);
  }

  const problems = await query;

  if (!includeComponents) {
    return { problems };
  }

  // When includeComponents=true, we need to add componentLanguageTotals and componentStatusTotals
  // for the filtered+limited result set

  // Extract problem IDs from the filtered and limited problems
  const problemIds = problems.map(p => p.id);
  if (problemIds.length === 0) {
    return {
      problems,
      metadata: {
        componentLanguageTotals: {},
        componentStatusTotals: {},
      },
    };
  }

  // Query components for these problems
  const components = await db('components')
    .select('language', 'status')
    .whereIn('problem_id', problemIds);

  // Count totals by language and status
  const componentLanguageTotals = _.countBy(components, 'language');
  const componentStatusTotals = _.countBy(components, 'status');

  return {
    problems,
    metadata: {
      componentLanguageTotals,
      componentStatusTotals,
    },
  };
}

module.exports = {
  listProblems,
};
